import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,t as a}from"./chunks/template-generator-advanced.CleIDHrl.js";const o=JSON.parse(`{"title":"创建项目","description":"关于如何使用 Fabric 模板模组生成器创建新的模组项目的逐步指南。","frontmatter":{"title":"创建项目","description":"关于如何使用 Fabric 模板模组生成器创建新的模组项目的逐步指南。","authors":["Cactooz","IMB11","radstevee","Thomas1034​"],"files":[]},"headers":[],"relativePath":"zh_cn/develop/getting-started/creating-a-project.md","filePath":"translated/zh_cn/develop/getting-started/creating-a-project.md","lastUpdated":1771183440000}`);var s={name:`zh_cn/develop/getting-started/creating-a-project.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">创建项目 <a class="header-anchor" href="#h1" aria-label="Permalink to “创建项目”">​</a></h1><p>Fabric 提供了一种简单的方法来使用 Fabric 模板模组生成器来创建新的模组项目——如果你愿意，你可以使用示例模组代码仓库手动创建一个新项目，请参考 <a href="#manual-project-creation">手动创建项目</a> 章节。</p><h2 id="generating-a-project" tabindex="-1">生成项目 <a class="header-anchor" href="#generating-a-project" aria-label="Permalink to “生成项目”">​</a></h2><p>你可以使用 <a href="https://fabricmc.net/develop/template/" target="_blank" rel="noreferrer">Fabric 模板模组生成器</a>为你的模组生成一个新项目——你应该填写必要的字段，例如模组名称、包名以及你想开发的 Minecraft 版本。</p><p>包名应为小写，用点分隔，并保持唯一以避免与其他程序员的包冲突。 它通常被格式化为反向互联网域名，例如 <code>com.example.example-mod</code>。</p><div class="warning custom-block"><p class="custom-block-title">重要</p><p>请记住你的模组 ID！ 当你在这些文档中找到 <code>example-mod</code> ，尤其是在文件路径中时，你必须用你自己的替换它。</p><p>例如，如果你的模组 ID 是 <strong><code>my-cool-mod</code></strong>，则使用 <strong><code>resources/assets/my-cool-mod</code></strong> 而不是 <em><code>resources/assets/example-mod</code></em>。</p></div><p><img src="/assets/develop/getting-started/template-generator.png" alt="生成器预览图" loading="lazy"></p><p>如果你想使用 Kotlin 或 Fabric 的 Yarn 映射而不是默认的 Mojang 映射，或者想添加数据生成器，你可以在 <code>Advanced Options</code> 部分选择相应的选项。</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>本站提供的代码示例使用 <a href="./../migrating-mappings/#mappings">Mojang 的官方名称</a>。 如果你的模组使用的映射与这些文档编写的映射不同，你需要使用 <a href="https://mappings.dev/" target="_blank" rel="noreferrer">mappings.dev</a> 或 <a href="https://linkie.shedaniel.dev/mappings?namespace=yarn&amp;translateMode=ns&amp;translateAs=mojang_raw&amp;search=" target="_blank" rel="noreferrer">Linkie</a> 等网站转换示例。</p></div><p><img src="/assets/develop/getting-started/template-generator-advanced.png" alt="Advanced Options 部分" loading="lazy"></p><p>填写完所需字段后，单击 <code>Generate</code> 按钮，生成器将以 zip 文件的形式创建新项目供你使用。</p><p>你需要将这个 zip 文件解压到你想要的位置，然后在你的 IDE 中打开解压的文件夹。</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>在为你的项目选择路径时，你应该遵循以下规则：</p><ul><li>避免云存储目录（例如 Microsoft OneDrive）</li><li>避免非 ASCII 字符（例如表情符号、重音字母、汉字）</li><li>避免空格</li></ul><p>一个“良好”的路径示例可以是： <code>C:\\Projects\\YourProjectName</code></p></div><h2 id="manual-project-creation" tabindex="-1">手动创建项目 <a class="header-anchor" href="#manual-project-creation" aria-label="Permalink to “手动创建项目”">​</a></h2><div class="info custom-block"><p class="custom-block-title">前置条件</p><p>你需要安装 <a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git</a> 来克隆示例模组代码仓库。</p></div><p>如果不能使用 Fabric 模板模组生成器，可以按以下步骤手动创建新项目。</p><p>首先，使用 Git 克隆示例模组代码仓库：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/FabricMC/fabric-example-mod/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example-mod</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这将把代码仓库克隆到一个名为 <code>example-mod</code> 的新文件夹中。</p><p>然后你应该从克隆的代码仓库中删除 <code>.git</code> 文件夹，并·打开项目。 如果找不到 <code>.git</code> 文件夹，你需要在你的文件资源管理器中启用显示隐藏文件。</p><p>在你的 IDE 中打开了项目之后，IDEA 会自动加载项目的 Gradle 配置并执行必要的初始化任务。</p><p>强调一遍，如上所述，如果你收到一个关于 Gradle 构建脚本的通知，你应该点击 <code>Import Gradle Project</code> 按钮。</p><h3 id="modifying-the-template" tabindex="-1">修改模板 <a class="header-anchor" href="#modifying-the-template" aria-label="Permalink to “修改模板”">​</a></h3><p>导入项目后，你应该修改项目的详细信息以匹配你的模组的信息：</p><ul><li>修改项目的 <code>gradle.properties</code> 文件，把 <code>maven_group</code> 和 <code>archive_base_name</code> 修改为匹配你的模组的信息。</li><li>修改 <code>fabric.mod.json</code> 文件，把 <code>id</code>、<code>name</code> 和 <code>description</code> 修改为匹配你的模组的信息。</li><li>确保更新 Minecraft、映射、Fabric Loader 和 Fabric Loom 的版本——所有这些都可以通过 <a href="https://fabricmc.net/develop/" target="_blank" rel="noreferrer">https://fabricmc.net/develop/</a> 查询，以匹配你希望的目标版本。</li></ul><p>你还可以修改包名和模组的主类来匹配你的模组的详细信息。</p>`,26)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};